async function handleOrderConfirmed(payload: OrderConfirmedPayload): Promise<void> {
  const carrier: ShippingCarrier = selectCarrier(payload.shippingAddress, payload.estimatedWeight);
  const estimatedDelivery: Date = calculateEstimatedDelivery(carrier, payload.shippingAddress);
  const shipment = this.shipmentRepository.create({orderId: payload.orderId, trackingNumber: generateTrackingNumber(), carrier: carrier, destination: payload.shippingAddress, weight: payload.estimatedWeight, status: ShipmentStatus.Pending, estimatedDelivery: estimatedDelivery});
  await this.shipmentRepository.save(shipment);
  for (const item of payload.items) {
    const entity = this.shipmentItemRepository.create({shipment: shipment, productId: item.productId, quantity: item.quantity});
    await this.shipmentItemRepository.save(entity);
  }
  const entity = this.shipmentEventRepository.create({shipment: shipment, timestamp: new Date(), status: ShipmentStatus.Pending, location: 'Warehouse', description: 'Shipment created, awaiting pickup'});
  await this.shipmentEventRepository.save(entity);
  eventEmitter.emit('ShipmentCreated', new ShipmentCreatedEvent({ shipmentId: shipment.id, orderId: payload.orderId }));
  await _getRedis().incr(format(new Date(), 'YYYY-MM-DD'));;
  console.info('shipment_created_from_order_confirmation');;
}

